/*
     SQL ID : MarkItemSettingDAO.mrkItmStngForProfModify
     설  명  : 성적항목설정 수정 - 교수
*/
UPDATE TB_LMS_MRK_ITM_STNG
SET
    MRK_RFLTRT = #{mrkRfltrt}
    , MRK_OYN    = #{mrkOyn}
    , MDFR_ID    = #{mdfrId}
    , MOD_DTTM   = FN_DTTM()
WHERE SBJCT_ID = #{sbjctId}
    AND MRK_ITM_TYCD = #{mrkItmTycd}
    AND MRK_ITM_USEYN = 'Y'
